// UNSAFE: Fragment.const with user input — SQL injection risk
def unsafeUsers(role: String): Query0[String] =
  Fragment.const(s"SELECT name FROM users WHERE role = '$role'").query[String]

// SAFE: sql"" interpolator — values become JDBC prepared parameters
def safeUsers(role: String): Query0[String] =
  sql"SELECT name FROM users WHERE role = $role".query[String]

// Dynamic predicates stay safe via fr"" composition
def usersWithFilter(role: Option[String]): Fragment =
  sql"SELECT name FROM users" ++
    role.map(r => fr"WHERE role = $r").getOrElse(Fragment.empty)

