sealed trait AppError
case class NotFound(id: String)    extends AppError
case class ParseError(msg: String) extends AppError

def findUser(id: String): Either[AppError, User] =
  if (id.isEmpty) Left(NotFound(id)) else Right(User(id, "Alice"))

def parseAge(s: String): Either[AppError, Int] =
  scala.util.Try(s.toInt).toEither.left.map(e => ParseError(e.getMessage))

def loadProfile(id: String, ageStr: String): Either[AppError, Profile] =
  for {
    user <- findUser(id)
    age  <- parseAge(ageStr)
  } yield Profile(user, age)

// Opaque type — erased to Long at bytecode, zero heap allocation
opaque type UserId = Long
object UserId:
  def apply(id: Long): UserId = id
  extension (id: UserId) def raw: Long = id

// Boxing trap: List[Int] wraps each Int as java.lang.Integer
val boxed: List[Int] = List(1, 2, 3)

// Unboxed: Array[Int] compiles to JVM int[], no heap per element
val unboxed: Array[Int] = Array(1, 2, 3)

// @specialized eliminates boxing in generic hot-path classes
class Ring[@specialized(Int, Long) A](val value: A)

import kamon.Kamon
import scala.concurrent.Future
import scala.concurrent.ExecutionContext.Implicits.global

object PaymentService {
  Kamon.init()

  private val processed = Kamon.counter("payments.processed").withoutTags()
  private val latency   = Kamon.histogram("payments.latency.ms").withTag("env", "prod")

  def charge(amount: BigDecimal): Future[Either[String, String]] =
    Future {
      val t0     = System.currentTimeMillis()
      val result = Right(s"tx-${System.nanoTime()}")
      latency.record(System.currentTimeMillis() - t0)
      processed.increment()
      result
    }
}
